SELECT g.基本工事コード, g.基本工事名, g.工事コード, g.工事名, g.枝番工事コード, g.追加工事名称, kt.施工管轄組織名, g.担当者名, g.着工 AS 着工日, g.完成 AS 完成日, g.工事価格, kt.粗利益額 AS 受注時粗利額, IIf(Nz(kt.工事価格, 0) = 0, Null, kt.粗利益額 / kt.工事価格) AS 受注時粗利率, g.予定利益 AS 原価S粗利額, g.粗利率 AS 原価S粗利率, [受注時粗利率] - [原価S粗利率] AS 粗利率差, g.直接工事費 AS 原価直接工事費, g.[既払高：総額] AS 既払直接工事費, g.今後支払予定, g.当月より前の支払金額, g.当月支払金額, g.当月以降予定金額, IIf(Abs(Nz([粗利率差], 0)) > 0.2, "粗利率エラー", Null) AS err粗利率差, IIf(Nz([既払直接工事費], 0) <> Nz([当月より前の支払金額], 0) + Nz([当月支払金額], 0), "当月支払金額エラー", Null) AS err当月支払, IIf(Nz([既払直接工事費], 0) + Nz([今後支払予定], 0) <> Nz([当月より前の支払金額], 0) + Nz([当月支払金額], 0) + Nz([当月以降予定金額], 0), "当月以降支払金額エラー", Null) AS err当月以降予定金額, IIf(Not IsNull([完成]) AND Nz([今後支払予定], 0) - Nz([当月以降予定金額], 0) <> 0 AND DateDiff("m", [完成], Date()) >= 2 AND [完成] < DateSerial(Year(Date()), Month(Date()), 1), "支払予定" & DateDiff("m", [完成], Date()) & "月超過エラー", Null) AS err完工日超過支払
FROM at_原価S_枝番工事 AS g LEFT JOIN q_Icube_WithMngNo AS kt ON (g.管理番号 = kt.管理番号) AND (g.工事コード = kt.工事コード)
ORDER BY kt.施工管轄組織コード, g.工事コード;
